    78→	r.authorizationRuleResolver.VisitRulesFor(ctx, requestAttributes.GetUser(), requestAttributes.GetNamespace(), ruleCheckingVisitor.visit)
    79→	if ruleCheckingVisitor.allowed {
    80→		return authorizer.DecisionAllow, ruleCheckingVisitor.reason, nil
    81→	}
